const BODY_HEAD_CRITICAL_ANGLE: number = 12;
const MAX_BODY_ANGLE: number = 10;
const DELETE_SWIPE_HEAD_WIDTH: number = 64;//删除滑动
const DELETE_SWIPE_BODY_WIDTH: number = 120;//删除滑动
