      theme: this.isThemeActive ? defaultCustomTheme : undefined,
      // 设置对话框主标题
      primaryTitle: $r('app.string.new_group_source'),
      // 设置对话框内容构建器
      contentBuilder: () => {
        this.NewGroupAccountDialog();
      },
      // 设置对话框按钮
      buttons: [
        {
          // 取消按钮
          value: $r('app.string.dialog_cancel'), // 按钮文本
          // 取消按钮点击事件
