            return;
          } else {
            // 设置创建群组参数为确认状态
            this.createGroupParams.ISCREATE = 1;
            // 打点记录用户确认创建群组事件
            DotUtil.getInstance().contactDot(this.createGroupParams, CREATE_GROUP_EVENT);

            // 检查群组名称是否已存在
            if (this.mPresenter.ifGroupExist(value)) {
