        .id('ContactListView_Contacts_delete_MenuItem')
        .onClick(() => {
          //从群组移除
          if (typeof item.member.member.contactId === 'string' && item.member.member.contactId !== '') {
            this.presenter.removeMemberByContactId(Number(item.member.member.contactId))
          } else {
