  releaseResource() {
    Log.info(TAG, 'start release resource');
    if (CheckEmptyUtils.isEmptyArr<FileModel>(this.imageSources)) {
      return;
    }
    for (let imageModel of this.imageSources) {
      imageModel.imageSource.release();
    }
