  connectCountDown() {
    this.connectCount--
    if (this.connectCount === Constants.COUNTDOWN_ALARM_TO_FAIL) {
      this.connectConfirmDialogCtl.close()
    } else if (this.connectCount === Constants.NUMBER_0 && !this.isConnected) {
      this.connectionFailed()
    }
  }

