          Notification({ touchMoveCallback: (data) => this.onTouchMove(data) })
            .transition(this.mNotificationInsert)
            .transition(this.mNotificationDelete)
        }
        if (this.showComponentName === DropdownPanelComponentName.CONTROL_CENTER) {
