import { HMSliderPlayerController } from '../controller/HMSliderPlayerController';
import { HMSliderPlayerDataSource, HMSliderPlayerIDataSource } from '../datasource/HMSliderPlayerIDataSource';
import { HMVideoSliderPlayer } from './HMVideoSliderPlayer';
import { JSON } from '@kit.ArkTS';
import { CommonConstant } from '../constant/CommonConstant';

@Component
export struct HMSliderPlayer {
  @State curIndex: number = 0;
  @State foldStatus: number = 0;
  private datasource: HMSliderPlayerIDataSource = new HMSliderPlayerIDataSource(new Array());
  private swiperController: SwiperController = new SwiperController();
  private hmSliderPlayerController? = new HMSliderPlayerController();
  private options?: HMSliderPlayerOptions;

  build() {
    Stack({ alignContent: Alignment.TopStart }) {
      Swiper(this.swiperController) {
        LazyForEach(this.datasource, (item: HMSliderPlayerDataSource, index: number) => {
          if (item.type == 'video') {
            HMVideoSliderPlayer({
              index: index,
              datasource: item,
              curIndex: this.curIndex,
              foldStatus: this.foldStatus
            })
          }
        }, (item: HMSliderPlayerDataSource, index: number) => JSON.stringify(item) + index)
      }
      .cachedCount(CommonConstant.DEFAULT_SWIPER_CACHE_COUNT)
      .width(CommonConstant.FULL_PERCENT_WIDTH)
      .height(CommonConstant.FULL_PERCENT_HEIGHT)
      .vertical(true)
      .loop(false)
      .curve(Curve.Ease)
      .duration(CommonConstant.DURATION_TIME)
      .indicator(false)
      .backgroundColor(Color.Black)
      .onAnimationStart((index: number, targetIndex: number) => {
        this.curIndex = targetIndex;
      })
    }
  }
}

/**
 * HMSliderPlayer的配置参数
 */
export class HMSliderPlayerOptions {
}

