import { SliderPlayerSize } from "HMSliderPlayer";
import { CommonConstant } from "../constant/CommonConstant"
import { LiveCommentsData, LiveCommentsModel } from "../utils/CommonUtils"
import { DialogComponentData } from "./DialogComponent";

@Component
export struct Comments {
  @ObjectLink dialogComponentData: DialogComponentData;
  @StorageLink('isBindSheetShow') isBindSheetShow: boolean = false
  @StorageLink('changeVideoHeight') videoHeight: string | number = CommonConstant.FULL_PERCENT_HEIGHT
  @State firstIndex: number = 0
  @StorageLink('displayWidth') displayWidth: number = 0
  @StorageLink('displayHeight') displayHeight: number = 0
  private commentListData: LiveCommentsData[] = new LiveCommentsModel().getLiveCommentsList()
  private closeAnimation(removeDialog: () => void, videoComponentOption: SliderPlayerSize) {
    this.dialogComponentData.y = CommonConstant.LIVE_COMMENTS_TRANSLATE_Y_ZERO
    this.dialogComponentData.x = CommonConstant.LIVE_COMMENTS_TRANSLATE_X_FULL
    animateTo({
      duration: CommonConstant.DURATION_TIME, onFinish: () => {
        removeDialog();
      }
    }, () => {
      this.dialogComponentData.x = CommonConstant.LIVE_COMMENTS_TRANSLATE_X_ZERO
      this.dialogComponentData.y = CommonConstant.LIVE_COMMENTS_TRANSLATE_Y_ZERO
      animateTo({ duration: CommonConstant.DURATION_TIME }, () => {
        if (this.displayWidth > CommonConstant.PHONE_WIDTH && this.displayWidth <= CommonConstant.FOLD_PHONE_WIDTH) {
          this.dialogComponentData.x = CommonConstant.LIVE_COMMENTS_TRANSLATE_X_FULL
          videoComponentOption.width = CommonConstant.FULL_PERCENT_WIDTH
        }else if (this.displayWidth <= CommonConstant.PHONE_WIDTH){
          this.dialogComponentData.y = CommonConstant.LIVE_COMMENTS_TRANSLATE_Y_FULL
          videoComponentOption.height = CommonConstant.FULL_PERCENT_HEIGHT;
        }
      })
      this.dialogComponentData.verticalScreenData.isShow = true;
    })
  }

  build() {
    RelativeContainer() {
      Column() {
        // 评论区顶部
        Flex({ direction: FlexDirection.Row, justifyContent: FlexAlign.SpaceBetween, alignItems: ItemAlign.Center }) {
          if (this.displayWidth > CommonConstant.PHONE_WIDTH && this.displayWidth <= CommonConstant.FOLD_PHONE_WIDTH) {
            Row() {
              Text(CommonConstant.FOLD_LIVE_COMMENTS_TEXT[0])
                .fontSize(CommonConstant.FOLD_LIVE_COMMENTS_TEXT_FONT_SIZE[0])
                .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                .margin({ right: CommonConstant.FOLD_LIVE_COMMENTS_TEXT_RIGHT_MARGIN })
              Text(CommonConstant.FOLD_LIVE_COMMENTS_TEXT[1])
                .fontSize(CommonConstant.FOLD_LIVE_COMMENTS_TEXT_FONT_SIZE[1])
            }
          } else {
            Text(CommonConstant.LIVE_COMMENTS_TEXT)
              .fontSize(CommonConstant.LIVE_COMMENTS_TEXT_FONTSIZE)
              .fontWeight(CommonConstant.CUSTOM_FONT_WEIGHT)
          }
          Image(CommonConstant.IMAGE_CLOSE)
            .width(CommonConstant.LIVE_COMMENTS_CLOSE_WIDTH)
            .onClick(() => {
              this.dialogComponentData.hmSliderController.closeDialog((videoComponentOption: SliderPlayerSize,
                removeDialog: () => void) => {
                this.closeAnimation(removeDialog, videoComponentOption)
              })
            })
        }
        .padding({ left: CommonConstant.LIVE_COMMENTS_PADDING, right: CommonConstant.LIVE_COMMENTS_PADDING })
        .width(CommonConstant.FULL_PERCENT_WIDTH)
        .height(CommonConstant.TEN_PERCENT_HEIGHT)

        // 评论区内容
        List({ space: CommonConstant.LIVE_COMMENTS_LIST_SPACE }) {
          ForEach(this.commentListData, (item: LiveCommentsData, index: number) => {
            ListItem() {
              Row() {
                Image(item.getAvatar())
                  .width(CommonConstant.LIVE_COMMENTS_AVATAR_WIDTH)
                  .margin({ left: CommonConstant.LIVE_COMMENTS_LEFT_MARGIN })
                Column() {
                  Flex({ justifyContent: FlexAlign.SpaceBetween, alignItems: ItemAlign.Center }) {
                    Text(item.getUserName())
                      .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                    Row() {
                      Image(item.getLikeIcon())// Image(item.getLikeIcon())
                        .width(CommonConstant.LIVE_COMMENTS_LIKE_WIDTH)
                        .margin({ bottom: CommonConstant.LIVE_COMMENTS_BOTTOM_MARGIN })
                      Text(`${item.getLikeNum()}`)
                        .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                    }
                    .justifyContent(FlexAlign.Center)
                    .alignItems(VerticalAlign.Top)
                    .width(CommonConstant.TEN_PERCENT_WIDTH)
                  }

                  Text(item.getCommentContent())
                    .margin({
                      top: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN,
                      bottom: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN
                    })
