import { DialogData, OnBackPressCallback } from 'HMSliderPlayer';
import { CommonConstant } from '../constant/CommonConstant';
import { DialogComponentData } from '../pages/Index';
import { LiveCommentsData, LiveCommentsModel } from '../utils/CommonUtils';
import { CommentsData } from './ViewScreenComponent';

@Component
export struct Comments {
  @Prop dialogData: DialogData;
  private removeDialog: () => void = null!;
  private onBackPressCallback: OnBackPressCallback = null!;
  @Prop dialogComponentData: CommentsData = null!;
  @StorageLink('isBindSheetShow') isBindSheetShow: boolean = false;
  @StorageLink('changeVideoHeight') videoHeight: string | number = CommonConstant.FULL_PERCENT_HEIGHT;
  @StorageLink('displayWidth') displayWidth: number = 0;
  @StorageLink('displayHeight') displayHeight: number = 0;
  @StorageLink('isTabShow') isTabShow: boolean = true;
  @StorageProp('bottomRectHeight') bottomRectHeight: number = 0;
  @StorageProp('topRectHeight') topRectHeight: number = 0;
  @State firstIndex: number = 0;
  private commentListData: LiveCommentsData[] = new LiveCommentsModel().getLiveCommentsList();

  closeAnimation(removeDialog: () => void, dialogData: DialogData) {
    this.dialogComponentData.y = CommonConstant.LIVE_COMMENTS_TRANSLATE_Y_ZERO;
    this.dialogComponentData.x = CommonConstant.LIVE_COMMENTS_TRANSLATE_X_FULL;
    animateTo({
      duration: CommonConstant.DURATION_TIME, onFinish: () => {
        removeDialog();
      }
    }, () => {
      this.dialogComponentData.y = CommonConstant.LIVE_COMMENTS_TRANSLATE_Y_ZERO;
      animateTo({ duration: CommonConstant.DURATION_TIME }, () => {
        if (this.displayWidth > CommonConstant.PHONE_WIDTH && this.displayWidth <= CommonConstant.FOLD_PHONE_WIDTH) {
          this.dialogComponentData.x = CommonConstant.TWENTY_FULL_PERCENT_X;
          dialogData.sliderPlayAttribute.width = CommonConstant.FULL_PERCENT_WIDTH;
          this.isTabShow = true;
        } else if (this.displayWidth <= CommonConstant.PHONE_WIDTH) {
          this.dialogComponentData.y = CommonConstant.LIVE_COMMENTS_TRANSLATE_Y_FULL;
          dialogData.sliderPlayAttribute.height = CommonConstant.FULL_PERCENT_HEIGHT;
          this.isTabShow = true;
        }
      });
    });
  }

  build() {
    RelativeContainer() {
      Flex({ direction: FlexDirection.Column }) {
        // 评论区顶部
        Flex({ direction: FlexDirection.Row, justifyContent: FlexAlign.SpaceBetween, alignItems: ItemAlign.Center }) {
          if (this.displayWidth > CommonConstant.PHONE_WIDTH && this.displayWidth <= CommonConstant.FOLD_PHONE_WIDTH) {
            Row() {
              Text(CommonConstant.FOLD_LIVE_COMMENTS_TEXT[0])
                .fontSize(CommonConstant.FOLD_LIVE_COMMENTS_TEXT_FONT_SIZE[0])
                .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                .margin({ right: CommonConstant.FOLD_LIVE_COMMENTS_TEXT_RIGHT_MARGIN });
              Text(CommonConstant.FOLD_LIVE_COMMENTS_TEXT[1])
                .fontSize(CommonConstant.FOLD_LIVE_COMMENTS_TEXT_FONT_SIZE[1]);
            };
          } else {
            Text(CommonConstant.LIVE_COMMENTS_TEXT)
              .fontSize(CommonConstant.LIVE_COMMENTS_TEXT_FONTSIZE)
              .fontWeight(CommonConstant.CUSTOM_FONT_WEIGHT);
          }
          Image(CommonConstant.IMAGE_CLOSE)
            .width(CommonConstant.LIVE_COMMENTS_CLOSE_WIDTH)
            .onClick(() => {
              this.closeAnimation(this.removeDialog, this.dialogData);
            });
        }
        .margin({ top: CommonConstant.LIVE_COMMENTS_TEXT_MARGIN, bottom: CommonConstant.LIVE_COMMENTS_TEXT_MARGIN })
        .width(CommonConstant.FULL_PERCENT_WIDTH)
        .height(CommonConstant.TEN_PERCENT_HEIGHT)
        .expandSafeArea([SafeAreaType.SYSTEM], [SafeAreaEdge.TOP, SafeAreaEdge.BOTTOM]);

        // 评论区内容
        List({ space: CommonConstant.LIVE_COMMENTS_LIST_SPACE }) {
          ForEach(this.commentListData, (item: LiveCommentsData, index: number) => {
            ListItem() {
              Row() {
                Image(item.getAvatar())
                  .width(CommonConstant.LIVE_COMMENTS_AVATAR_WIDTH)
                  .margin({ left: CommonConstant.LIVE_COMMENTS_LEFT_MARGIN });
                Column() {
                  Flex({ justifyContent: FlexAlign.SpaceBetween, alignItems: ItemAlign.Center }) {
                    Text(item.getUserName())
                      .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR);
                    Row() {
                      Text(`${item.getLikeNum()}`)
                        .fontSize(CommonConstant.LIVE_COMMENTS_LIKE_NUM_FONT_SIZE)
                        .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                        .margin({ right: CommonConstant.LIVE_COMMENTS_LIKE_NUM_MARGIN_RIGHT });
                      Image(item.getLikeIcon())
                        .width(CommonConstant.LIVE_COMMENTS_LIKE_WIDTH)
                        .margin({ bottom: CommonConstant.LIVE_COMMENTS_BOTTOM_MARGIN });
                    }
                    .justifyContent(FlexAlign.Center)
                    .alignItems(VerticalAlign.Center)
                    .width(CommonConstant.TWENTY_PERCENT_WIDTH);
                  };

                  Text(item.getCommentContent())
                    .margin({
                      top: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN,
                      bottom: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN
                    });
                  Row() {
                    Text(item.getDate() + '·')
                      .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                      .fontSize(CommonConstant.LIVE_COMMENTS_REPLY_TEXT_FONTSIZE);
                    Text(item.getFrom())
                      .fontColor(CommonConstant.LIVE_COMMENTS_FONT_COLOR)
                      .fontSize(CommonConstant.LIVE_COMMENTS_REPLY_TEXT_FONTSIZE);
                    Text(this.firstIndex == index ?
                      CommonConstant.LIVE_COMMENTS_REPLY_NUM + CommonConstant.LIVE_COMMENTS_REPLY :
                    CommonConstant.LIVE_COMMENTS_REPLY)
                      .padding(CommonConstant.LIVE_COMMENTS_LIKE_NUM_MARGIN_RIGHT)
                      .textAlign(TextAlign.Center)
                      .fontSize(CommonConstant.LIVE_COMMENTS_REPLY_TEXT_FONTSIZE)
                      .fontColor(this.firstIndex == index ? CommonConstant.LIVE_COMMENTS_FONT_COLOR :
                      CommonConstant.LIVE_COMMENTS_REPLY_FONT_COLOR)
                      .backgroundColor(this.firstIndex == index ? CommonConstant.LIVE_COMMENTS_REPLY_BACKGROUND_COLOR :
                      Color.Transparent)
                      .borderRadius(this.firstIndex == index ? CommonConstant.LIVE_COMMENTS_REPLY_BACKGROUND_RADIUS :
                        null)
                      .fontWeight(this.firstIndex == index ? null : CommonConstant.CUSTOM_FONT_WEIGHT);
                  };

                  if (this.firstIndex == index) {
                    Flex({ direction: FlexDirection.Column, justifyContent: FlexAlign.SpaceEvenly }) {
                      Text(CommonConstant.LIVE_COMMENTS_REPLY_TEXT[0])
                        .margin({
                          top: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN
                        });
                      Text(CommonConstant.LIVE_COMMENTS_REPLY_TEXT[1])
                        .fontColor(CommonConstant.LIVE_COMMENTS_LOOK_REPLY_FONT_COLOR)
                        .margin({
                          top: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN,
                          bottom: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN
                        });
                    }
                    .width(CommonConstant.FULL_PERCENT_WIDTH)
                    .padding({
                      left: CommonConstant.LIVE_COMMENTS_PADDING,
                      right: CommonConstant.LIVE_COMMENTS_PADDING
                    })
                    .margin({ top: CommonConstant.LIVE_COMMENTS_REPLY_MARGIN_TOP })
                    .backgroundColor(CommonConstant.LIVE_COMMENTS_REPLY_BACKGROUND_COLOR)
                    .borderRadius(CommonConstant.LIVE_COMMENTS_REPLY_BACKGROUND_RADIUS);
                  }
                }
                .alignItems(HorizontalAlign.Start)
                .width(CommonConstant.SEVENTY_PERCENT_WIDTH)
                .margin({
                  left: CommonConstant.LIVE_COMMENTS_LEFT_MARGIN,
                  bottom: CommonConstant.LIVE_COMMENTS_USERNAME_BOTTOM_MARGIN
                });
              }
              .alignItems(VerticalAlign.Top);
            };
          });
        }
        .width(CommonConstant.FULL_PERCENT_WIDTH)
        .height(CommonConstant.SEVENTY_FIVE_PERCENT_HEIGHT)
        .expandSafeArea([SafeAreaType.SYSTEM], [SafeAreaEdge.TOP, SafeAreaEdge.BOTTOM]);

        // 评论区底部
        Flex({ direction: FlexDirection.Row, justifyContent: FlexAlign.SpaceAround, alignItems: ItemAlign.Center }) {
          TextInput({ placeholder: CommonConstant.LIVE_COMMENTS_TEXT_INPUT_PLACEHOLDER })
            .width(CommonConstant.EIGHTY_PERCENT_WIDTH);
          Image(CommonConstant.LIVE_COMMENTS_BOTTOM_IMAGE)
            .width(CommonConstant.TEN_PERCENT_WIDTH);
        }
        .expandSafeArea([SafeAreaType.SYSTEM], [SafeAreaEdge.TOP, SafeAreaEdge.BOTTOM])
        .width(CommonConstant.FULL_PERCENT_WIDTH)
        .height(CommonConstant.TEN_PERCENT_HEIGHT);
      }
      .backgroundColor(CommonConstant.LIVE_COMMENTS_BACKGROUND_COLOR)
      .padding({ left: CommonConstant.LIVE_COMMENTS_PADDING, right: CommonConstant.LIVE_COMMENTS_PADDING })
      .width(this.displayWidth < CommonConstant.PHONE_WIDTH ? CommonConstant.FULL_PERCENT_WIDTH :
      CommonConstant.FIFTY_PERCENT_WIDTH)
      .height(this.displayWidth < CommonConstant.PHONE_WIDTH ? CommonConstant.SEVENTY_PERCENT_HEIGHT :
      CommonConstant.FULL_PERCENT_HEIGHT)
      .translate({
        x: this.displayWidth < CommonConstant.PHONE_WIDTH ? CommonConstant.ZERO_PERCENT_WIDTH :
        this.dialogComponentData.x,
        y: this.displayWidth < CommonConstant.PHONE_WIDTH ? this.dialogComponentData.y :
        CommonConstant.ZERO_PERCENT_WIDTH
      })
      .borderRadius({
        topLeft: this.displayWidth > CommonConstant.PHONE_WIDTH &&
          this.displayWidth <= CommonConstant.FOLD_PHONE_WIDTH ?
        CommonConstant.FAST_SPEED_BOTTOM_BORDER_RADIUS : CommonConstant.FAST_SPEED_TOP_BORDER_RADIUS,
        topRight: this.displayWidth > CommonConstant.PHONE_WIDTH &&
          this.displayWidth <= CommonConstant.FOLD_PHONE_WIDTH ?
        CommonConstant.FAST_SPEED_BOTTOM_BORDER_RADIUS : CommonConstant.FAST_SPEED_TOP_BORDER_RADIUS,
      })
      .alignRules({
        bottom: { anchor: '__container__', align: VerticalAlign.Bottom },
        left: { anchor: '__container__', align: HorizontalAlign.Start }
      });
    }
    .backgroundColor(Color.Transparent)
  }
}

