import { HMLifecycleState, HMRouterMgr } from '@hadss/hmrouter';

interface Menu {
  title: string;
  url: string;
}

@Component
export struct NavBarContent {
  private data: Menu[] = [
    {
      title: 'HMRouter的路由方案',
      url: 'https://developer.huawei.com/consumer/cn/forum/topic/0201164055842970001?fid=0109140870620153026',
    }, {
    title: '性能优化工具使用案例1',
    url: 'https://developer.huawei.com/consumer/cn/forum/topic/0212162230984762938?fid=0109140870620153026'
  }, {
    title: '性能优化工具使用案例2',
    url: 'https://developer.huawei.com/consumer/cn/forum/topic/0203162230595861169?fid=0109140870620153026'
  }, {
    title: '性能优化工具使用案例3',
    url: 'https://developer.huawei.com/consumer/cn/forum/topic/0201162229621817598?fid=0109140870620153026'
  }, {
    title: '性能优化工具使用案例4',
    url: 'https://developer.huawei.com/consumer/cn/forum/topic/0201162227549580593?fid=0109140870620153026'
  }

  ];
  private reConfirm: boolean = false;
  private hideTitle: boolean = false;
  @BuilderParam NavBarDesc: () => void;

  aboutToAppear(): void {
    const owner = HMRouterMgr.getCurrentLifecycleOwner();
    // 拦截navbar页面退出场景
    owner?.addObserver(HMLifecycleState.onBackPressed, (ctx) => {
      if (this.reConfirm === false) {
        this.reConfirm = true;
        setTimeout(() => {
          this.reConfirm = false;
        }, 1500)
        ctx.uiContext.getPromptAction().showToast({
          message: '再次返回退出页面',
          duration: 1500
        })
        return true;
      } else {
        return false
      }
    })
  }

  build() {
    Column() {
      this.NavBarDesc?.()
      if (!this.hideTitle) {
        Text('一多案例')
          .textAlign(TextAlign.Start)
          .margin({ bottom: 12, left: 26 })
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
      }

      List({ space: 8 }) {
        ForEach(this.data, (item: Menu) => {
          ListItem() {
            Row() {
              Text(item.title)
                .fontSize(16)
                .textAlign(TextAlign.Start)

                .layoutWeight(1)
                Image($r("app.media.chevron_right")).width(12).height(24);

