import { CardAttr, WaterFlowDataSource } from './common/waterflow/WaterFlowDataSource';
import { CardComponent } from './CardComponent';
import { Constants } from './common/utils/Constants';
import { HMRouter, HMRouterMgr } from '@hadss/hmrouter';
import { HMRouterTransitions } from '@hadss/hmrouter-transitions';

@HMRouter({ pageUrl: 'CardLongTakePageOne' })
@Component
export struct CardLongTakePageOne {
  @State dataSource: WaterFlowDataSource = new WaterFlowDataSource();
  @State columnWidth: number = 0;
  @State columnType: string = '';
  @StorageProp('currentBreakpoint') @Watch('upDateColumnData') currentBreakpoint: string = '';

  aboutToAppear(): void {
    for (let i = 0; i < 100; i++) {
      this.dataSource.pushData(new CardAttr());
    }
    this.upDateColumnData();
  }

  private upDateColumnData(): void {
    let currentBreakpoint: string | undefined = AppStorage.get('currentBreakpoint');
    if (currentBreakpoint == 'xs' || currentBreakpoint == 'sm') {
      this.columnType = '1fr 1fr';
    } else if (currentBreakpoint == 'md') {
      this.columnType = '1fr 1fr 1fr';
    } else {
      this.columnType = '1fr 1fr 1fr 1fr';
    }
  }

  build() {
    Stack() {
      WaterFlow() {
        LazyForEach(this.dataSource, (item: CardAttr, index: number) => {
          FlowItem() {
            CardComponent({
              indexValue: index.toString(),
              cardAttr: item,
              onColumnClicked: () => {
                const animator =
                  HMRouterTransitions.cardLongTake(Constants.getFlowItemIdByIndex(index.toString()), 'test', {
                    onTransitionStart: () => {
                      console.log('onTransitionStart');
                    },
                    onTransitionEnd: () => {
                      console.log('onTransitionEnd');
                    }
                  });
                HMRouterMgr.push({ pageUrl: 'CardLongTakePageTwo', param: index, animator: animator });
              }
            });
          }
          .borderRadius(9)
          .width('100%')
          .clip(true)
          .id(Constants.getFlowItemIdByIndex(index.toString()))
        }, (item: string) => item);
      }
      .cachedCount(4)
      .columnsTemplate(this.columnType)
      .columnsGap(5)
      .rowsGap(5)
      .width('100%')
      .height('100%');
    }
    .size({ width: '100%', height: '100%' })
    .padding({ left: 10, right: 10 });
  }
}

