import { Constants } from '../constants/Constants';
import { RectInfo_px } from '../utils/ComponentAttrUtils';
import { WindowUtils } from '../utils/WindowUtils';
import { image } from '@kit.ImageKit';

const INIT_OVERLAY_COLOR = '#00000000';

const FINAL_OVERLAY_COLOR = '#50000000';

export interface LongTakeTransitionOptions {
  onTransitionStart?: () => void;
  onTransitionEnd?: () => void;
}

// Encapsulate the custom one-mirror transition animation so that other interfaces requiring a custom one-mirror transition can directly reuse it, reducing workload
@Observed
export class LongTakeSession {
  public navDestinationBgColor: ResourceColor = INIT_OVERLAY_COLOR;

  public snapShotImage: image.PixelMap | undefined = undefined;

  public snapShotOpacity: number = 1;

  public postPageOpacity: number = 1;

  public translateX: number = 0;

  public translateY: number = 0;

  public scaleValue: number = 1;

  public clipWidth: Dimension = '100%';

  public clipHeight: Dimension = '100%';

  public radius: BorderRadiuses | Length | LocalizedBorderRadiuses = 16;

  public positionXValue: number = 0;

  public positionYValue: number = 0;

  public snapShotSize: SizeOptions = { width: '100%', height: '100%' };

  public snapShotPositionX: number = 0;

  public snapShotPositionY: number = 0;

  private animationCount: number = 0;

  private initScale: number = 1;

  private initTranslateX: number = 0;

  private initTranslateY: number = 0;

  private initClipWidth: Dimension = 0;

  private initClipHeight: Dimension = 0;

  private initPositionValueX: number = 0;

  private initPositionValueY: number = 0;

  private initBorderRadius: BorderRadiuses | Length | LocalizedBorderRadiuses = 0;

  public recoverPrePage: Function | undefined = () => {};

  public initParams(postPageSharedComponentId: string, cardItemInfo_px: RectInfo_px, cardItemComponentId: string): void {
    let sourceNode = WindowUtils.window.getUIContext().getFrameNodeById(cardItemComponentId);
    let postNode = WindowUtils.window.getUIContext().getFrameNodeById(postPageSharedComponentId);
    let stackNode = WindowUtils.window.getUIContext().getFrameNodeById(Constants.POST_PAGE_STACK_ID);
    let snapShotStackNode = WindowUtils.window.getUIContext().getFrameNodeById(Constants.POST_PAGE_STACK_ID);

    let isWindowLayoutFullScreen: boolean = WindowUtils.window.getWindowProperties().isLayoutFullScreen;

    let stackPosition_vp = stackNode?.getPositionToWindowWithTransform();
    let stackSize_px = stackNode?.getMeasuredSize();
    let stackCenterX_px = vp2px(stackPosition_vp?.x) + (stackSize_px?.width!) / 2;

    let snapShotStackPositionToWindow_vp = snapShotStackNode?.getPositionToWindowWithTransform();

    if (!postPageSharedComponentId || !postNode || !snapShotStackNode) {
      if (!stackNode?.getMeasuredSize().width || !stackNode?.getMeasuredSize().height) {
        this.setFinalStatus();
        return;
      }

      let initScaleX = cardItemInfo_px.width / stackSize_px?.width!;
      let initScaleY = cardItemInfo_px.height / stackSize_px?.height!;

      this.initPositionValueY = (stackPosition_vp?.y! != 0) ? 0
        : (isWindowLayoutFullScreen ? 0 : -px2vp(WindowUtils.topAvoidAreaHeight_px));

      if (initScaleX >= initScaleY) {
        this.initScale = initScaleX;
        this.initTranslateX = px2vp(cardItemInfo_px.left);
        this.initClipWidth = px2vp(stackSize_px?.width);
        this.initClipHeight = px2vp((cardItemInfo_px.height) / this.initScale);
        this.snapShotSize = { width: px2vp(stackSize_px?.width) };
        this.initTranslateY = px2vp(cardItemInfo_px.top);
      } else {
        this.initScale = initScaleY;
        this.initTranslateY = px2vp(cardItemInfo_px.top);
        this.initClipHeight = px2vp(stackSize_px?.height);
        this.initClipWidth = px2vp((cardItemInfo_px.width) / this.initScale);
        this.initTranslateX = px2vp(cardItemInfo_px.left);
        this.snapShotSize = { height: px2vp(stackSize_px?.height) };
      }
    } else {
      let postNodePositionX_vp = postNode.getPositionToWindowWithTransform().x;
      let postNodePositionY_vp = postNode.getPositionToWindowWithTransform().y;
      let postNodeWidth_px = postNode.getMeasuredSize().width;
      let postNodeHeight_px = postNode.getMeasuredSize().height;


      this.initPositionValueX = -postNodePositionX_vp + snapShotStackPositionToWindow_vp?.x!;
      this.initPositionValueY = -postNodePositionY_vp + snapShotStackPositionToWindow_vp?.y!;
      this.snapShotPositionY = postNodePositionY_vp - snapShotStackPositionToWindow_vp?.y!
        - ((stackPosition_vp?.y!) != 0 ? 0 :
          (isWindowLayoutFullScreen ? 0 : px2vp(WindowUtils.topAvoidAreaHeight_px)));
      this.snapShotPositionX = postNodePositionX_vp - snapShotStackPositionToWindow_vp?.x!;

      this.initScale = cardItemInfo_px.width / postNodeWidth_px;

      let inspectorInfo = sourceNode?.getInspectorInfo();
      this.initBorderRadius = inspectorInfo ? (inspectorInfo as ESObject).$attrs.borderRadius : 0;

      if (typeof this.initBorderRadius === 'string') {
        this.initBorderRadius = parseFloat(this.initBorderRadius) / this.initScale
      }

      this.initClipHeight = px2vp(cardItemInfo_px.height / this.initScale);
      this.initTranslateY = px2vp(cardItemInfo_px.top);
      this.initClipWidth = px2vp(postNodeWidth_px);
      this.snapShotSize = { width: px2vp(postNodeWidth_px) };
      this.initTranslateX = px2vp(cardItemInfo_px.left);
    }
  }

  public doEnterAnimation(transitionProxy?: NavigationTransitionProxy): void {
    this.scaleValue = this.initScale;
    this.translateX = this.initTranslateX;
    this.clipWidth = this.initClipWidth;
    this.clipHeight = this.initClipHeight;
    this.translateY = this.initTranslateY;
    this.positionYValue = this.initPositionValueY;
    this.positionXValue = this.initPositionValueX;
    this.radius = this.initBorderRadius;

    let animationCount = ++this.animationCount;

    // Start executing the animation effect
    animateTo({
      duration: 220,
      curve: Curve.EaseInOut,
      onFinish: () => {
        if (animationCount === this.animationCount) {
          this.radius = 0;
        }
        if (transitionProxy) {
          transitionProxy.finishTransition();
        }
      }
    }, () => {
      this.scaleValue = 1.0;
      this.translateX = 0;
      this.translateY = 0;
      this.clipWidth = '100%';
      this.clipHeight = '100%';
      this.positionYValue = 0;
      this.positionXValue = 0;
      this.navDestinationBgColor = FINAL_OVERLAY_COLOR;
    })

    animateTo({
      delay: 50,
      duration: 75,
      curve: Curve.Sharp,
    }, () => {
      this.snapShotOpacity = 0;
    })

    animateTo({
      duration: 100,
      curve: Curve.Sharp,
    }, () => {
      this.postPageOpacity = 1.0;
    })
  }

  public doBackAnimation(transitionProxy?: NavigationTransitionProxy): void {
    ++this.animationCount;

    animateTo({
      duration: 220,
      curve: Curve.EaseInOut,
      onFinish: () => {
        this.recoverPrePage?.();
        if (transitionProxy) {
          transitionProxy.finishTransition();
        }
      }
    }, () => {
      this.scaleValue = this.initScale;
      this.translateX = this.initTranslateX;
      this.clipWidth = this.initClipWidth;
      this.clipHeight = this.initClipHeight;
      this.translateY = this.initTranslateY;
      this.radius = this.initBorderRadius;
      this.positionXValue = this.initPositionValueX;
      this.positionYValue = this.initPositionValueY;
      this.navDestinationBgColor = INIT_OVERLAY_COLOR;
    })

    animateTo({
      delay: 50,
      duration: 150,
      curve: Curve.Friction,
    }, () => {
      this.snapShotOpacity = 1;
    })

    animateTo({
      delay: 100,
      duration: 100,
      curve: Curve.Friction,
    }, () => {
      this.postPageOpacity = 0;
    })
  }

  // When not using a custom transition, set the state to the normal final state
  public setFinalStatus(): void {
    this.navDestinationBgColor = INIT_OVERLAY_COLOR;
    this.clipWidth = '100%';
    this.clipHeight = '100%';
    this.snapShotOpacity = 0;
    this.postPageOpacity = 1;
    this.radius = 0;
  }
}

