import { LongTakeSession } from './LongTakeSession';
import { Constants } from '../constants/Constants';
import { image } from '@kit.ImageKit';
import { HMRouterTransitions } from '../HMRouterTransitions';

@Component
export struct LongTakeTransitionDelegate{
  @BuilderParam contentBuilder: () => void;

  @ObjectLink longTakeSession: LongTakeSession;

  @State snapShotImage: image.PixelMap | undefined = undefined;

  aboutToAppear(): void {
    if (this.longTakeSession.snapShotImage) {
      this.snapShotImage = this.longTakeSession.snapShotImage;
    }
  }

  build() {
    Column() {
      Stack({ alignContent: Alignment.TopStart }) {
        // The original content of the popup page, add transparency control for its display during the animation process
        Stack({ alignContent: Alignment.TopStart }) {
          this.contentBuilder()
        }
        .opacity(this.longTakeSession.postPageOpacity)
        .position({ x: this.longTakeSession.positionXValue, y: this.longTakeSession.positionYValue })

        if (this.longTakeSession.snapShotSize) {
          Stack({ alignContent: Alignment.Top }) {
            // Used to display the screenshot of the card clicked on the previous page
            Image(this.snapShotImage)
              .size(this.longTakeSession.snapShotSize)
              .objectFit(ImageFit.Auto)
              .opacity(this.longTakeSession.snapShotOpacity)
              .syncLoad(true) // Wait for the screenshot to load synchronously to avoid issues such as flashing white or sudden changes
                // The position here should be the distance from the screenshot location to the expanded page image location
              .position({
                x: this.longTakeSession.snapShotPositionX,
                y: this.longTakeSession.snapShotPositionY
              })
              .focusable(false)
              .enabled(false)
          }
          .focusable(false)
          .enabled(false)
          .id(Constants.POST_PAGE_SNAPSHOT_STACK_ID)
          .width('100%')
          .position({ x: this.longTakeSession.positionXValue, y: this.longTakeSession.positionYValue })
        }
      }
      .id(Constants.POST_PAGE_STACK_ID)
      .scale({
        x: this.longTakeSession.scaleValue,
        y: this.longTakeSession.scaleValue,
        centerX: 0,
        centerY: 0
      })
      .translate({ x: this.longTakeSession.translateX, y: this.longTakeSession.translateY })
      .width(this.longTakeSession.clipWidth)
      .height(this.longTakeSession.clipHeight)
      .borderRadius(this.longTakeSession.radius)
      .expandSafeArea([SafeAreaType.SYSTEM])
      .clip(true)
    }
    .width('100%')
    .height('100%')
    .alignItems(HorizontalAlign.Start)
    .justifyContent(FlexAlign.Start)
    .expandSafeArea([SafeAreaType.SYSTEM])
    .backgroundColor(this.longTakeSession.navDestinationBgColor)
  }
}

