@Component
export default struct StaggeredGridLayoutHelper {
  @State layoutColor: Color | string = 0xFF86345A //布局颜色
  @State innerColor: Color | string = 0x22EEEEEE //内部颜色
  @State layoutContent: any[] = [] //内容元素
  @State layoutHeight: number = 1800 //布局高度
  @State differentHeight: boolean = true //是否同高
  @State columnsTemplate: string = '1fr'
  @State rowsTemplate: string = '1fr'
  @State columnsGap: number = 5
  @State rowsGap: number = 5
  @State borderWidth: number = 1
  @State topPadding: number = 5 //上内边距
  @State rightPadding: number = 5 //右内边距
  @State bottomPadding: number = 5 //下内边距
  @State leftPadding: number = 5 //左内边距

  @State topMargin: number = 5 //上外边距
  @State rightMargin: number = 5 //右外边距
  @State bottomMargin: number = 5 //下外边距
  @State leftMargin: number = 5 //左外边距

  @State isStaggered: boolean = false //是否为交错宫格
  private leftArr: any[] = [] //左列
  private leftTotalHeight = 0 //左列总高
  private rightArr: any[] = [] //右列
  private rightTotalHeight = 0 //右列总高
  @State rowSpace: number = 5 //沿水平方向的间距
  @State itemSpace: number = 5 //列表项间距

  aboutToAppear() {
    if (this.isStaggered == true) {
      if (this.layoutContent[0].layoutAspectRatio == 0) {
        this.leftArr.push(this.layoutContent[0])
        this.leftTotalHeight = this.layoutContent[0].layoutHeight
      } else {
        this.leftArr.push(this.layoutContent[0])
        this.leftTotalHeight = ((720 - this.leftMargin - this.rightMargin) / 2 - this.leftPadding - (this.rowSpace / 2)) / 2 / this.layoutContent[0].layoutAspectRatio + this.itemSpace
      }

      if (this.layoutContent[1].layoutAspectRatio == 0) {
        this.rightArr.push(this.layoutContent[1])
        this.rightTotalHeight = this.layoutContent[1].layoutHeight
      } else {
        this.rightArr.push(this.layoutContent[1])
        this.rightTotalHeight = ((720 - this.leftMargin - this.rightMargin) / 2 - this.rightPadding - (this.rowSpace / 2)) / 2 / this.layoutContent[1].layoutAspectRatio + this.itemSpace
      }

      for (let i = 2; i < this.layoutContent.length; i++) {
        if (this.leftTotalHeight >= this.rightTotalHeight) { //左边比右边高，往右边放
          if (this.layoutContent[i].layoutAspectRatio == 0) {
            this.rightArr.push(this.layoutContent[i])
            this.rightTotalHeight += this.layoutContent[i].layoutHeight
          } else {
            this.rightArr.push(this.layoutContent[i])
            this.rightTotalHeight += ((720 - this.leftMargin - this.rightMargin) / 2 - this.rightPadding - (this.rowSpace / 2)) / 2 / this.layoutContent[i].layoutAspectRatio + this.itemSpace
          }
        } else { //右边比左边高，往左边放
          if (this.layoutContent[i].layoutAspectRatio == 0) {
            this.leftArr.push(this.layoutContent[i])
            this.leftTotalHeight += this.layoutContent[i].layoutHeight
          } else {
            this.leftArr.push(this.layoutContent[i])
            this.leftTotalHeight += ((720 - this.leftMargin - this.rightMargin) / 2 - this.leftPadding - (this.rowSpace / 2)) / 2 / this.layoutContent[i].layoutAspectRatio + this.itemSpace
          }
        }
      }
    }
  }

  build() {
    if(this.isStaggered == true){
      Column() {
        Row({ space: this.rowSpace }) {
          List({ space: this.itemSpace, initialIndex: 0 }) {
            ForEach(this.leftArr, (item: any) => {
              ListItem() {
                Text(`${item.layoutText}`)
                  .width('100%')
                  .height('100%')
                  .backgroundColor('#33EEEEEE')
                  .border({ width: 1, color: '#000000', radius: 0, style: BorderStyle.Solid })
                  .fontColor('#999999')
                  .fontSize(25)
                  .fontWeight(FontWeight.Bold)
                  .textAlign(TextAlign.Center)
                  .textOverflow({ overflow: TextOverflow.Ellipsis })
              }
              .height(`${item.layoutHeight}`)
              .aspectRatio(item.layoutAspectRatio)
            }, (item: any) => item.toString())
          }
          .edgeEffect(EdgeEffect.None)
          .layoutWeight(1)

          List({ space: this.itemSpace, initialIndex: 0 }) {
            ForEach(this.rightArr, (item: any) => {
              ListItem() {
                Text(`${item.layoutText}`)
                  .width('100%')
                  .height('100%')
                  .backgroundColor('#33EEEEEE')
                  .border({ width: 1, color: '#000000', radius: 0, style: BorderStyle.Solid })
                  .fontColor('#999999')
                  .fontSize(25)
                  .fontWeight(FontWeight.Bold)
                  .textAlign(TextAlign.Center)
                  .textOverflow({ overflow: TextOverflow.Ellipsis })
              }
              .height(`${item.layoutHeight}`)
              .aspectRatio(item.layoutAspectRatio)
            }, (item: any) => item.toString())
          }
          .edgeEffect(EdgeEffect.None)
          .layoutWeight(1)
        }
        .backgroundColor(this.layoutColor)
        .alignItems(VerticalAlign.Top)
        .padding({
          top: this.topPadding,
          right: this.rightPadding,
          bottom: this.bottomPadding,
          left: this.leftPadding
        })
      }
      .margin({
        top: this.topMargin,
        right: this.rightMargin,
        bottom: this.bottomMargin,
        left: this.leftMargin
      })
    }else{
      Column() {
        Grid() {
          ForEach(this.layoutContent, (item: any, index: number) => {
            GridItem() {
              Flex({
                direction: FlexDirection.Column,
                wrap: FlexWrap.Wrap,
                justifyContent: FlexAlign.Start,
                alignItems: ItemAlign.Start,
                alignContent: FlexAlign.Start
              }) {
                Text(`${item.layoutText}`)
                  .width('100%')
                  .height(`${item.layoutTextHeight}`)
                  .backgroundColor(this.innerColor)
                  .border({ width: this.borderWidth, color: '#000000', radius: 0, style: BorderStyle.Solid })
                  .fontColor('#999999')
                  .fontSize(25)
                  .fontWeight(FontWeight.Bold)
                  .textAlign(TextAlign.Center)
                  .textOverflow({ overflow: TextOverflow.Ellipsis })
              }
            }
            .width('100%')
            .height(this.differentHeight ? '100%' : index % 2 == 0 ? '100%' : '80%')
            .border({ width: 1, color: '#000000', radius: 0, style: BorderStyle.Solid })
            .columnStart(Number(`${item.columnStart}`) == 0 ? 0 : item.columnStart)
            .columnEnd(Number(`${item.columnEnd}`) == 0 ? 0 : item.columnEnd)
          }, (item: any, index: number) => item.toString())
        }
        .width('100%')
        .height(this.layoutHeight)
        .backgroundColor(this.layoutColor)
        .padding({
          top: this.topPadding,
          right: this.rightPadding,
          bottom: this.bottomPadding,
          left: this.leftPadding
        })
        .columnsTemplate(this.columnsTemplate)
        .rowsTemplate(this.rowsTemplate)
        .columnsGap(this.columnsGap)
        .rowsGap(this.rowsGap)
      }
      .margin({
        top: this.topMargin,
        right: this.rightMargin,
        bottom: this.bottomMargin,
        left: this.leftMargin
      })
    }
  }
}

