import { RubiksCube } from '@ohos/ohos_svg/';
import {SVGExample} from '@ohos/ohos_svg/'
import { SVGManager } from '@ohos/ohos_svg/'
import {SVGImageView} from '@ohos/ohos_svg/'

interface Cherry {
  x: number;
  y: number;
  scaleX: number;
  scaleY: number;
}

@Entry
@Component
struct Index {

  private svgManager: SVGManager = SVGManager.getInstance();
  @State countDownFrom: number = 0
  @State dashOffset: number = 0
  @State countDownFromImage: number = 0
  @State dashOffsetImage: number = 0
  private timerId: number = -1
  private ANIM_DURATION: number = 3000; // milliseconds
  private ANIM_PATH_LENGTH: number = 3018; // the total length of the doodle path
  private ANIM_DURATION_IMAGE: number = 1500; // milliseconds
  private ANIM_LINES_DRAW_END: number = 0.9;
  private ANIM_IMAGE_FADE_START: number = 0.8;
  @State cssStr: string = ""
  @State legoCss: string = "";
  @State rubiskCss: string = "";
  @State private showType: number = 1;
  @State private menuWidth: string = "70%";
  @State private cherrys: Cherry[] = [];
  @State private showNumber: number = 0;
  private cube: RubiksCube;
  private isAdd: boolean = false;
  private pathLengths = new Map([['#plate-lg', 2794], ['#plate-sm', 1903], ['.orange', 903]]);
  private xCount: number = 0;

  private timingCycleColor(): void  {
    this.countDownFrom = 0;
    this.timerId = setInterval(() => {
      this.dashOffset = Math.round(this.ANIM_PATH_LENGTH * this.countDownFrom);
      this.cssStr = "#doodle { stroke-dasharray: " + this.ANIM_PATH_LENGTH + " " + this.ANIM_PATH_LENGTH + "; stroke-dashoffset: " + this.dashOffset + "; }";
      if(this.countDownFrom <= 0){
        this.countDownFrom = 0
        this.isAdd = true;
      }else if(this.countDownFrom >= 1){
        this.countDownFrom = 1
        this.isAdd = false;
      }
      if(this.isAdd){
        this.countDownFrom += 0.004
      }else{
        this.countDownFrom -= 0.004
      }
    }, 1) // decr counter by 1 every second
  }

  private timingCycleImage(): void  {
    this.countDownFromImage = 0;
    this.timerId = setInterval(() => {
      var imageOpacity = this.mapRangeClamped(this.countDownFromImage, this.ANIM_IMAGE_FADE_START, 1, 0, 1);
      this.cssStr = "#image { opacity: " + imageOpacity + "; } "
      var dashOffsetImage = null;
      for (let [key, value] of this.pathLengths.entries()) {
        dashOffsetImage = Math.round(this.mapRangeClamped(this.countDownFromImage, 0, this.ANIM_LINES_DRAW_END, value, 0));
        var nn = key + " { stroke-dasharray: " + value + " " + value + "; stroke-dashoffset: " + dashOffsetImage + "; } "
        this.cssStr = this.cssStr + nn
      }
      if (this.countDownFromImage >= 1) {
        this.countDownFromImage = 0
        clearInterval(this.timerId)
      }
      this.countDownFromImage += 0.01
    }, 1) // decr counter by 1 every second
  }

  private mapRangeClamped(value: number, inMin: number, inMax: number, outMin: number, outMax: number): number
  {
    var value: number = Math.max(inMin, Math.min(inMax, value));
    var inRange: number = inMax - inMin;
    var outRange: number = outMax - outMin;
    var num: number = outMin + (value - inMin) * outRange / inRange
    var result: number = Number(Math.floor(num * 100) / 100)
    return result;
  }

  public aboutToAppear(){

  }

  public aboutToDisappear(): void {
    if (this.timerId > 0) {
      clearTimeout(this.timerId)
      this.timerId = -1
    }
  }

  build() {
    Stack() {
      Flex({ direction: FlexDirection.Column }) {
        if (this.showType == 1) {
          Stack({ alignContent: Alignment.Top }) {
            Text("Hello!")
              .fontSize(18)
            Text("This is a demonstration app for the OhosSVG library, which allows you to include SVG images in your apps.")
              .fontSize(14)
              .fontColor("#333333")
              .margin({ top: 20 })
              .textAlign(TextAlign.Center)
            Stack() {
              SVGImageView({ svgString: SVGExample.androidLogoSvg, isScaledDensity: true }) //AndroidSVG_logo
            }
            .margin({ top: 200 })
            .scale({x:1,y:-1})
          }.padding(40)
        } else if (this.showType == 2) {
          Flex({ direction: FlexDirection.Column, alignItems: ItemAlign.Center }) {
            Text("About this app")
              .fontSize(18)
          }.padding(40)
        } else if (this.showType == 3) {
          Stack({ alignContent: Alignment.Top }) {
            Text("Render an SVG to an Ohos Bitmap at various sizes. Tap to regenerate the image.")
              .fontSize(14)
              .fontColor("#333333")
              .margin({ top: 10 })
              .textAlign(TextAlign.Center)
            Stack() {
              ForEach(this.cherrys, (item: Cherry) => {
                SVGImageView({
                  svgString: SVGExample.cherrySvg,
                  x: item.x,
                  y: item.y,
                  scaleX: item.scaleX,
                  scaleY: item.scaleY
                }) //cherry
              }, (item: Cherry) => (item.x + "").toString())
            }
            .width("100%")
            .margin({ top: 50 })
            .scale({x:0.2,y:0.2})
          }.padding(40).height("100%")
        } else if (this.showType == 4) {
          Stack({ alignContent: Alignment.Center }) {
            Stack() {
              SVGImageView({
                svgString: SVGExample.rubiksSvg,
                cssStr: this.rubiskCss,
                isUpdateCss: true,
                updateCssTime:10
              }) //rubiks-cube
            }
            .onClick(() => {
              this.cube.shuffleOneStep();
              this.updateCubeCSS(this.cube);
            })
            .scale({x:1,y:-1})
            .translate({x:0,y:-300})
            Text("Tap either image to change its colours")
              .fontSize(14)
              .fontColor("#333333")
            Stack() {
              SVGImageView({ svgString: SVGExample.logoSvg, cssStr: this.legoCss, isUpdateCss: true}) //lego
            }
            .onClick(() => {
              var brickColours = ["#1698ec", "#fef134", "#95e881", "#ea272e"]
              for (var i = brickColours.length - 1; i > 0; i--) {
                var index = Math.round(Math.random() * (brickColours.length - 1))
                var temp = brickColours[index]
                brickColours[index] = brickColours[i];
                brickColours[i] = temp;
              }
              this.legoCss = ".brick1 { fill:" + brickColours[0] + "; } .brick2 { fill:" + brickColours[1] + "; } .brick3 { fill:" + brickColours[2] + "; } .brick4 { fill:" + brickColours[3] + "; }";
            })
            .scale({x:1,y:-1})
            .translate({x:0,y:200})
          }.height("100%")
        } else if (this.showType == 5) {
          Flex({ direction: FlexDirection.Column }) {
            Text("Animated line drawing using stroke-dashoffset")
              .fontSize(14)
              .fontColor("#333333")
            Flex() {
              SVGImageView({ svgString: SVGExample.doodle, cssStr: this.cssStr, isUpdateCss: true ,updateCssTime:1}) //7doodle
            }
            .scale({ x: 1, y: -1 })
            .translate({x:-80,y:-150})
          }.padding(40).height("100%")
        } else if (this.showType == 6) {
          Stack({ alignContent:Alignment.Top }) {
            Text("Another animated line drawing example.\nTap to restart animation.")
              .fontSize(14)
              .fontColor("#333333")
            Stack() {
              SVGImageView({
                svgString: SVGExample.orange,
                cssStr: this.cssStr,
                isUpdateCss: true,
                updateCssTime: 1
              })
            }
            .translate({ x: -160, y: -100 })
            .scale({x:0.4,y:0.4})
            .onClick(() => {
              this.cssStr = "ellipse, path, image { opacity: 0; }"
              this.countDownFromImage = 0
              this.dashOffsetImage = 0
              this.timingCycleImage();
            })
          }.height("100%")
          .padding({ top:40})
          .margin({ bottom:20 })
        }
      }.padding({ top: 50})

      //titleBar
      Flex({ direction: FlexDirection.Row,alignItems:ItemAlign.Center }) {
        Image($r('app.media.menu'))
          .width(40)
          .height(40)
          .padding({right:20})
          .onClick(() => {
            this.menuWidth = "70%"
          })
        Text("OhosSVG Sample App")
          .margin({ left: 20 })
          .fontSize(18)
          .fontColor(Color.White)
          .fontWeight(FontWeight.Bold)
      }.padding({ top: 20, bottom: 20, left: 20, right: 20 })
      .backgroundColor("#4050B5")
      .position({ x: 0, y: 0 })

      //leftMenu
      Flex({ direction: FlexDirection.Row }) {
        Flex({ direction: FlexDirection.Column }) {
          Flex({ direction: FlexDirection.Column, justifyContent: FlexAlign.Center, alignItems: ItemAlign.Start }) {
            Image($r('app.media.ic_launcher_round'))
              .width(70)
              .height(70)
              .borderRadius(35)
              .objectFit(ImageFit.Contain)
            Text("OhosSVG sample app")
              .fontSize(14)
              .fontColor(Color.White)
              .margin({ top: 10, bottom: 5 })
            Text("SVG rendering library for Ohos")
              .fontSize(12)
              .fontColor("#B4E0F0")
          }.width("100%")
          .height("20%")
          .backgroundColor("#2BA79C")
          .padding({ left: 20, right: 20 })

          Flex({ direction: FlexDirection.Column }) {
            Flex({ direction: FlexDirection.Column }) {
              Text("Home")
                .fontSize(14)
                .padding({ top: 15, bottom: 15 })
                .width("100%")
                .onClick(() => {
                  this.showType = 1
                  this.initData();
                })
              Text("About")
                .fontSize(14)
                .padding({ top: 15, bottom: 15 })
                .width("100%")
                .onClick(() => {
                  this.showType = 2
                  this.initData();
                })
            }.padding({ left: 20, top: 10, bottom: 10, right: 20 })
