              }.padding({ left: 20, top: 10, bottom: 10, right: 20 })
              .width("100%")
              .onClick(() => {
                clearInterval(this.timerId)
                this.showType = 3
                this.cherrys.length = 0;
                this.initData();
                this.timerId = setInterval(() => {
                  this.xCount += 50;
                  if (this.cherrys.length < 10) {
                    var x = Math.round(Math.random() * this.xCount);
