      .height("100%")
      .backgroundColor("#80000000")
      .onClick(() => {
        this.menuWidth = "0%"
      })
      .visibility(this.menuWidth == "0%"?Visibility.Hidden:Visibility.Visible)
    }
  }

  private updateCubeCSS(cube: RubiksCube) {
    var css: string = "";
    css += this.doFace(css, cube, RubiksCube.TOP, 'T');
    css += this.doFace(css, cube, RubiksCube.LEFT, 'L');
    css += this.doFace(css, cube, RubiksCube.RIGHT, 'R');
    this.rubiskCss = css;
  }

  faceColours:string[] = ["#f9ca2e", "#c72e33", "#297537", "#f36021", "#255ea2", "#ffffff"];  // yellow, red, green, orange, blue, white

  private doFace(css: string, cube: RubiksCube, face: number, cssClassTilePrefix: string):string {
    for (var tile = 0; tile < 9; tile++) {
      css += ".";
      css += cssClassTilePrefix;
      css += tile;
      css += " {fill: ";
      css += this.faceColours[cube.getColour(face, tile)];
      css += "} ";
    }
    return css;
  }

  private initData(){
    clearInterval(this.timerId)
    this.menuWidth = "0%"
    this.cssStr = "";
    this.cube = new RubiksCube();
    this.legoCss = "";
    this.rubiskCss = "";
  }

}

